// Both ensures pin r1@ and r2@ to the same value parse_arg_as_end_point(arg@) =
// AbstractEndPoint{id: arg@}. Unfolding the view of EndPoint, this forces
// r1.id@ == arg@ and r2.id@ == arg@. We re-state these implications explicitly so
// that z3 has the right ground terms to instantiate any forall in
// det_parse_end_point_equal (which is over r1.id@/r2.id@), and we close with
// sequence extensionality (=~=) to lift pointwise equality to ==.
assert((r1@ == parse_arg_as_end_point(arg@) && r2@ == parse_arg_as_end_point(arg@))
    ==> r1.id@ == arg@);
assert((r1@ == parse_arg_as_end_point(arg@) && r2@ == parse_arg_as_end_point(arg@))
    ==> r2.id@ == arg@);
assert((r1@ == parse_arg_as_end_point(arg@) && r2@ == parse_arg_as_end_point(arg@))
    ==> r1.id@.len() == r2.id@.len());
assert((r1@ == parse_arg_as_end_point(arg@) && r2@ == parse_arg_as_end_point(arg@))
    ==> r1.id@ =~= r2.id@);
assert((r1@ == parse_arg_as_end_point(arg@) && r2@ == parse_arg_as_end_point(arg@))
    ==> r1.id@ == r2.id@);
assert((r1@ == parse_arg_as_end_point(arg@) && r2@ == parse_arg_as_end_point(arg@))
    ==> r1@ == r2@);
assert((r1@ == parse_arg_as_end_point(arg@) && r2@ == parse_arg_as_end_point(arg@))
    ==> forall|i: int| 0 <= i < r1.id@.len() ==> r1.id@[i] == r2.id@[i]);
